// // This module implements a D flip-flop with an XOR input, triggered on the negative edge of 'clk', and an active-low synchronous reset.
module top_module (
	input clk,
	input rst,
	input p,
	input q,
	output reg out);

	initial
		out = 0;

	always@(posedge clk) begin
		if (rst)
			out <= 1;
		else
			out <= p ^ q;
	end

endmodule
